304	void delay_us(volatile uint32_t us){
305	__HAL_TIM_SET_COUNTER(&htim1,0);  // set the counter value a
306	while (__HAL_TIM_GET_COUNTER(&htim1) < us);  // //Clock TIMx -> AHB/APB1 is set to 72MHz/presc+1   presc = 71
307	}
