309	//////////////////////////////////////////////
310	//////////////////delay_ns()//////////////////
311	//////////////////////////////////////////////
312	void delay_ns(uint32_t nanoseconds)
313	{
314	    // Get the starting cycle count
315	    uint32_t start_cycles = DWT->CYCCNT;
316	
317	    // Convert nanoseconds to the number of CPU clock cycles
318	    // Use `SystemCoreClock` to get the current CPU frequency.
319	    // Use 64-bit math to prevent overflow for large nanosecond values.
320	    uint32_t cycles = (uint32_t)(((uint64_t)nanoseconds * SystemCoreClock) / 1000000000);
321	
322	    // Busy-wait until the required number of cycles has passed
323	    while ((DWT->CYCCNT - start_cycles) < cycles);
324	}
