329	uint8_t degreesTo7BitPhase(float degrees) {
330	    // Normalize to 0-360 range
331	    while(degrees < 0) degrees += 360.0f;
332	    while(degrees >= 360.0f) degrees -= 360.0f;
333	
334	    // Convert to 7-bit (0-127)
335	    uint8_t phase_7bit = (uint8_t)((degrees / 360.0f) * 128.0f);
336	
337	    return phase_7bit % 128;
338	}
