354	void systemPowerUpSequence() {
355	    DIAG_SECTION("PWR: systemPowerUpSequence");
356	    uint8_t msg[] = "Starting Power Up Sequence...\r\n";
357	    HAL_UART_Transmit(&huart3, msg, sizeof(msg)-1, 1000);
358	
359	    // Step 1: Initialize ADTR1107 power sequence
360	    DIAG("PWR", "Step 1: initializeADTR1107Sequence()");
361	    if (!adarManager.initializeADTR1107Sequence()) {
362	        DIAG_ERR("PWR", "ADTR1107 power sequence FAILED -- calling Error_Handler()");
363	        uint8_t err[] = "ERROR: ADTR1107 power sequence failed!\r\n";
364	        HAL_UART_Transmit(&huart3, err, sizeof(err)-1, 1000);
365	        Error_Handler();
366	    }
367	    DIAG("PWR", "Step 1 OK: ADTR1107 sequence complete");
368	
369	    // Step 2: Initialize all ADAR1000 devices
370	    DIAG("PWR", "Step 2: initializeAllDevices()");
371	    if (!adarManager.initializeAllDevices()) {
372	        DIAG_ERR("PWR", "ADAR1000 initialization FAILED -- calling Error_Handler()");
373	        uint8_t err[] = "ERROR: ADAR1000 initialization failed!\r\n";
374	        HAL_UART_Transmit(&huart3, err, sizeof(err)-1, 1000);
375	        Error_Handler();
376	    }
377	    DIAG("PWR", "Step 2 OK: All ADAR1000 devices initialized");
378	
379	    // Step 3: Perform system calibration
380	    DIAG("PWR", "Step 3: performSystemCalibration()");
381	    if (!adarManager.performSystemCalibration()) {
382	        DIAG_WARN("PWR", "System calibration returned issues (non-fatal)");
383	        uint8_t warn[] = "WARNING: System calibration issues\r\n";
384	        HAL_UART_Transmit(&huart3, warn, sizeof(warn)-1, 1000);
385	    } else {
386	        DIAG("PWR", "Step 3 OK: System calibration passed");
387	    }
388	
389	    // Step 4: Set to safe TX mode
390	    DIAG("PWR", "Step 4: setAllDevicesTXMode()");
391	    adarManager.setAllDevicesTXMode();
392	    DIAG("PWR", "Step 4 OK: All devices set to TX mode");
393	
394	    uint8_t success[] = "Power Up Sequence Completed Successfully\r\n";
395	    HAL_UART_Transmit(&huart3, success, sizeof(success)-1, 1000);
396	    DIAG("PWR", "systemPowerUpSequence COMPLETE");
397	}
