399	void systemPowerDownSequence() {
400	    DIAG_SECTION("PWR: systemPowerDownSequence");
401	    uint8_t msg[] = "Starting Power Down Sequence...\r\n";
402	    HAL_UART_Transmit(&huart3, msg, sizeof(msg)-1, 1000);
403	
404	    // Step 1: Set all devices to RX mode (safest state)
405	    DIAG("PWR", "Step 1: setAllDevicesRXMode()");
406	    adarManager.setAllDevicesRXMode();
407	    HAL_Delay(10);
408	
409	    // Step 2: Disable PA power supplies
410	    DIAG("PWR", "Step 2: Disable PA 5V supplies (EN_P_5V0_PA1/PA2/PA3 LOW)");
411	    HAL_GPIO_WritePin(EN_P_5V0_PA1_GPIO_Port, EN_P_5V0_PA1_Pin | EN_P_5V0_PA2_Pin | EN_P_5V0_PA3_Pin, GPIO_PIN_RESET);
412	    HAL_Delay(10);
413	
414	    // Step 3: Set PA biases to safe values
415	    DIAG("PWR", "Step 3: Setting PA bias to safe value 0x20 on all 4 devices, 4 channels each");
416	    for (uint8_t dev = 0; dev < 4; dev++) {
417	        adarManager.adarWrite(dev, REG_PA_CH1_BIAS_ON, 0x20, BROADCAST_OFF);
418	        adarManager.adarWrite(dev, REG_PA_CH2_BIAS_ON, 0x20, BROADCAST_OFF);
419	        adarManager.adarWrite(dev, REG_PA_CH3_BIAS_ON, 0x20, BROADCAST_OFF);
420	        adarManager.adarWrite(dev, REG_PA_CH4_BIAS_ON, 0x20, BROADCAST_OFF);
421	    }
422	    HAL_Delay(10);
423	
424	    // Step 4: Disable LNA power supply
425	    DIAG("PWR", "Step 4: Disable LNA 3.3V supply (EN_P_3V3_ADTR LOW)");
426	    HAL_GPIO_WritePin(EN_P_3V3_ADTR_GPIO_Port, EN_P_3V3_ADTR_Pin, GPIO_PIN_RESET);
427	    HAL_Delay(10);
428	
429	    // Step 5: Set LNA bias to safe value
430	    DIAG("PWR", "Step 5: Setting LNA bias to 0x00 on all 4 devices");
431	    for (uint8_t dev = 0; dev < 4; dev++) {
432	        adarManager.adarWrite(dev, REG_LNA_BIAS_ON, 0x00, BROADCAST_OFF);
433	    }
434	    HAL_Delay(10);
435	
436	    // Step 6: Disable switch power supplies
437	    DIAG("PWR", "Step 6: Disable switch supplies (EN_P_3V3_VDD_SW, EN_P_3V3_SW LOW)");
438	    HAL_GPIO_WritePin(EN_P_3V3_VDD_SW_GPIO_Port, EN_P_3V3_VDD_SW_Pin, GPIO_PIN_RESET);
439	    HAL_GPIO_WritePin(EN_P_3V3_SW_GPIO_Port, EN_P_3V3_SW_Pin, GPIO_PIN_RESET);
440	    HAL_Delay(10);
441	
442	    uint8_t success[] = "Power Down Sequence Completed\r\n";
443	    HAL_UART_Transmit(&huart3, success, sizeof(success)-1, 1000);
444	    DIAG("PWR", "systemPowerDownSequence COMPLETE");
445	}
