507	void runRadarPulseSequence() {
508	    static int sequence_count = 0;
509	    char msg[50];
510	
511	    snprintf(msg, sizeof(msg), "Starting RADAR Sequence #%d\r\n", ++sequence_count);
512	    HAL_UART_Transmit(&huart3, (uint8_t*)msg, strlen(msg), 1000);
513	    DIAG("SYS", "runRadarPulseSequence #%d: m_max=%d n_max=%d y_max=%d",
514	         sequence_count, m_max, n_max, y_max);
515	
516	    // Configure for fast switching
517	    DIAG("BF", "Enabling fast-switch mode for beam sweep");
518	    adarManager.setFastSwitchMode(true);
519	
520	    int m = 1; // Chirp counter
521	    int n = 1; // Beam Elevation position counter
522	    int y = 1; // Beam Azimuth counter
523	
524	    // Main beam steering sequence
525	    for(int beam_pos = 0; beam_pos < 15; beam_pos++) {
526	    	HAL_GPIO_TogglePin(GPIOD, GPIO_PIN_9);// Notify FPGA of elevation change
527	    	DIAG("SYS", "Beam pos %d/15: elevation GPIO toggle, patterns matrix1/vector_0/matrix2", beam_pos);
528	        // Pattern 1: matrix1 (positive steering angles)
529	        adarManager.setCustomBeamPattern16(matrix1[beam_pos], ADAR1000Manager::BeamDirection::TX);
530	        adarManager.setCustomBeamPattern16(matrix1[beam_pos], ADAR1000Manager::BeamDirection::RX);
531	
532	        executeChirpSequence(m_max/2, T1, PRI1, T2, PRI2);
533	        m += m_max/2;
534	
535	        // Pattern 2: vector_0 (broadside)
536	        adarManager.setCustomBeamPattern16(vector_0, ADAR1000Manager::BeamDirection::TX);
537	        adarManager.setCustomBeamPattern16(vector_0, ADAR1000Manager::BeamDirection::RX);
538	
539	        executeChirpSequence(m_max/2, T1, PRI1, T2, PRI2);
540	        m += m_max/2;
541	
542	        // Pattern 3: matrix2 (negative steering angles)
543	        adarManager.setCustomBeamPattern16(matrix2[beam_pos], ADAR1000Manager::BeamDirection::TX);
544	        adarManager.setCustomBeamPattern16(matrix2[beam_pos], ADAR1000Manager::BeamDirection::RX);
545	
546	        executeChirpSequence(m_max/2, T1, PRI1, T2, PRI2);
547	        m += m_max/2;
548	
549	        // Reset chirp counter if needed
550	        if(m > m_max) m = 1;
551	
552	        n++;
553	        if(n > n_max) n = 1;
554	
555	    }
556	
557	    HAL_GPIO_TogglePin(GPIOD,GPIO_PIN_10);//Tell FPGA that there is a new azimuth
558	    DIAG("SYS", "Azimuth GPIO toggle (GPIOD pin 10), stepping motor");
559	
560	    y++; if(y>y_max)y=1;
561		  //Rotate stepper to next y position
562		  for(int k= 0;k<(int)(Stepper_steps/y_max);k++){
563			  HAL_GPIO_WritePin(STEPPER_CLK_P_GPIO_Port, STEPPER_CLK_P_Pin, GPIO_PIN_SET);
564			  delay_us(500);
565			  HAL_GPIO_WritePin(STEPPER_CLK_P_GPIO_Port, STEPPER_CLK_P_Pin, GPIO_PIN_RESET);
566			  delay_us(500);
567		  }
568	    DIAG("MOT", "Stepper moved %d steps for azimuth position y=%d", (int)(Stepper_steps/y_max), y);
569	
570	
571	
572	    snprintf(msg, sizeof(msg), "RADAR Sequence #%d Completed\r\n", sequence_count);
573	    HAL_UART_Transmit(&huart3, (uint8_t*)msg, strlen(msg), 1000);
574	    DIAG("SYS", "runRadarPulseSequence #%d COMPLETE", sequence_count);
575	}
