606	
607	typedef enum {
608	    ERROR_NONE = 0,
609	    ERROR_AD9523_CLOCK,
610	    ERROR_ADF4382_TX_UNLOCK,
611	    ERROR_ADF4382_RX_UNLOCK,
612	    ERROR_ADAR1000_COMM,
613	    ERROR_ADAR1000_TEMP,
614	    ERROR_IMU_COMM,
615	    ERROR_BMP180_COMM,
616	    ERROR_GPS_COMM,
617	    ERROR_RF_PA_OVERCURRENT,
618	    ERROR_RF_PA_BIAS,
619	    ERROR_STEPPER_MOTOR,
620	    ERROR_FPGA_COMM,
621	    ERROR_POWER_SUPPLY,
622	    ERROR_TEMPERATURE_HIGH,
623	    ERROR_MEMORY_ALLOC,
624	    ERROR_WATCHDOG_TIMEOUT,
625	    ERROR_COUNT  // must be last — used for bounds checking error_strings[]
626	} SystemError_t;
627	
628	static SystemError_t last_error = ERROR_NONE;
629	static uint32_t error_count = 0;
630	static bool system_emergency_state = false;
631	
632	// Error handler function
633	SystemError_t checkSystemHealth(void) {
634	    SystemError_t current_error = ERROR_NONE;
635	
636	    // 0. Watchdog: detect main-loop stall (checkSystemHealth not called for >60 s).
637	    //    Timestamp is captured at function ENTRY and updated unconditionally, so
638	    //    any early return from a sub-check below cannot leave a stale value that
639	    //    would later trip a spurious ERROR_WATCHDOG_TIMEOUT. A dedicated cold-start
640	    //    branch ensures the first call after boot never trips (last_health_check==0
641	    //    would otherwise make `HAL_GetTick() - 0 > 60000` true forever after the
642	    //    60-s mark of the init sequence).
643	    static uint32_t last_health_check = 0;
644	    uint32_t now_tick = HAL_GetTick();
645	    if (last_health_check == 0) {
646	        last_health_check = now_tick;          // cold start: seed only
647	    } else {
648	        uint32_t elapsed = now_tick - last_health_check;
649	        last_health_check = now_tick;          // update BEFORE any early return
650	        if (elapsed > 60000) {
651	            current_error = ERROR_WATCHDOG_TIMEOUT;
652	            DIAG_ERR("SYS", "Health check: Watchdog timeout (>60s since last check)");
653	            return current_error;
654	        }
655	    }
656	
657	    // 1. Check AD9523 Clock Generator
658	    static uint32_t last_clock_check = 0;
659	    if (HAL_GetTick() - last_clock_check > 5000) {
660	        GPIO_PinState s0 = HAL_GPIO_ReadPin(AD9523_STATUS0_GPIO_Port, AD9523_STATUS0_Pin);
661	        GPIO_PinState s1 = HAL_GPIO_ReadPin(AD9523_STATUS1_GPIO_Port, AD9523_STATUS1_Pin);
662	        DIAG_GPIO("CLK", "AD9523 STATUS0", s0);
663	        DIAG_GPIO("CLK", "AD9523 STATUS1", s1);
664	        if (s0 == GPIO_PIN_RESET || s1 == GPIO_PIN_RESET) {
665	            current_error = ERROR_AD9523_CLOCK;
666	            DIAG_ERR("CLK", "AD9523 clock health check FAILED (STATUS0=%d STATUS1=%d)", s0, s1);
667	            return current_error;
668	        }
669	        last_clock_check = HAL_GetTick();
670	    }
671	
672	    // 2. Check ADF4382 Lock Status
673	    bool tx_locked, rx_locked;
674	    if (ADF4382A_CheckLockStatus(&lo_manager, &tx_locked, &rx_locked) == ADF4382A_MANAGER_OK) {
675	        if (!tx_locked) {
676	            current_error = ERROR_ADF4382_TX_UNLOCK;
677	            DIAG_ERR("LO", "Health check: TX LO UNLOCKED");
678	            return current_error;
679	        }
680	        if (!rx_locked) {
681	            current_error = ERROR_ADF4382_RX_UNLOCK;
682	            DIAG_ERR("LO", "Health check: RX LO UNLOCKED");
683	            return current_error;
684	        }
685	    }
686	
687	    // 3. Check ADAR1000 Communication and Temperature
688	    for (int i = 0; i < 4; i++) {
689	        if (!adarManager.verifyDeviceCommunication(i)) {
690	            current_error = ERROR_ADAR1000_COMM;
691	            DIAG_ERR("BF", "Health check: ADAR1000 #%d comm FAILED", i);
692	            return current_error;
693	        }
694	
695	        float temp = adarManager.readTemperature(i);
696	        if (temp > 85.0f) {
697	            current_error = ERROR_ADAR1000_TEMP;
698	            DIAG_ERR("BF", "Health check: ADAR1000 #%d OVERTEMP %.1fC > 85C", i, temp);
699	            return current_error;
700	        }
701	    }
702	
703	    // 4. Check IMU Communication
704	    static uint32_t last_imu_check = 0;
705	    if (HAL_GetTick() - last_imu_check > 10000) {
706	        if (!GY85_Update(&imu)) {
707	            current_error = ERROR_IMU_COMM;
708	            DIAG_ERR("IMU", "Health check: GY85_Update() FAILED");
709	            return current_error;
710	        }
711	        last_imu_check = HAL_GetTick();
712	    }
713	
714	    // 5. Check BMP180 Communication
715	    static uint32_t last_bmp_check = 0;
716	    if (HAL_GetTick() - last_bmp_check > 15000) {
717	        double pressure = myBMP.getPressure();
718	        if (pressure < 30000.0 || pressure > 110000.0 || isnan(pressure)) {
719	            current_error = ERROR_BMP180_COMM;
720	            DIAG_ERR("SYS", "Health check: BMP180 pressure out of range: %.0f", pressure);
721	            return current_error;
722	        }
723	        last_bmp_check = HAL_GetTick();
724	    }
725	
726	    // 6. Check GPS Communication (30s grace period from boot / last valid fix)
727	    uint32_t gps_fix_age = um982_position_age(&um982);
728	    if (gps_fix_age > 30000) {
729	        current_error = ERROR_GPS_COMM;
730	        DIAG_WARN("SYS", "Health check: GPS no fix for >30s (age=%lu ms)", (unsigned long)gps_fix_age);
731	        return current_error;
732	    }
733	
734	    // 7. Check RF Power Amplifier Current
735	    if (PowerAmplifier) {
736	        for (int i = 0; i < 16; i++) {
737	            if (Idq_reading[i] > 2.5f) {
738	                current_error = ERROR_RF_PA_OVERCURRENT;
739	                DIAG_ERR("PA", "Health check: PA ch%d OVERCURRENT Idq=%.3fA > 2.5A", i, Idq_reading[i]);
740	                return current_error;
741	            }
742	            if (Idq_reading[i] < 0.1f) {
743	                current_error = ERROR_RF_PA_BIAS;
744	                DIAG_ERR("PA", "Health check: PA ch%d BIAS FAULT Idq=%.3fA < 0.1A", i, Idq_reading[i]);
745	                return current_error;
746	            }
747	        }
748	    }
749	
750	    // 8. Check System Temperature
751	    if (temperature > 75.0f) {
752	        current_error = ERROR_TEMPERATURE_HIGH;
753	        DIAG_ERR("SYS", "Health check: System OVERTEMP %.1fC > 75C", temperature);
754	        return current_error;
755	    }
756	
757	    // 9. Watchdog check is performed at function entry (see step 0).
758	
759	    if (current_error != ERROR_NONE) {
760	        DIAG_ERR("SYS", "checkSystemHealth returning error code %d", current_error);
761	    }
762	    return current_error;
763	}
