1511	  ax *= 6.10351e-5;   //2.0 / 32768.0;
1512	  ay *= 6.10351e-5;
1513	  az *= 6.10351e-5;
1514	
1515	  ax -= abias[0];   // Convert to g's, remove accelerometer biases
1516	  ay -= abias[1];
1517	  az -= abias[2];
1518	
1519	  gx *= 0.0152588f;   //500.0 / 32768.0;
1520	  gy *= 0.0152588f;
1521	  gz *= 0.0152588f;
1522	
1523	  gx -= gbias[0];   // Convert to degrees per seconds, remove gyro biases
1524	  gy -= gbias[1];
1525	  gz -= gbias[2];
1526	
1527	  mx *= 6.10351e-5;   //2.0 / 32768.0;
1528	  my *= 6.10351e-5;
1529	  mz *= 6.10351e-5;
1530	
1531	  mxc = M11*(mx-mbias[0]) + M12*(my-mbias[1]) +M13*(mz-mbias[2]);
1532	  myc = M21*(mx-mbias[0]) + M22*(my-mbias[1]) +M23*(mz-mbias[2]);
1533	  mzc = M31*(mx-mbias[0]) + M32*(my-mbias[1]) +M33*(mz-mbias[2]);
1534	
1535	  mx = mxc;
1536	  my = myc;
1537	  mz = mzc;
1538	
1539	  float norm = sqrt((mx*mx) + (my*my) + (mz*mz));
1540	  mx /=norm;
1541	  my /=norm;
1542	  mz /=norm;
