1545	  /*********************IMU Complementary Filter******************/
1546	  /***************************************************************/
1547	    RxAcc = ax;
1548	    RyAcc = ay;
1549	    RzAcc = az;
1550	
1551	    Rate_Ayz_1 = gx;
1552	    Rate_Axz_1 = gy;
1553	    Rate_Axy_1 = gz;
1554	
1555	    Rate_Ayz_1 = Rate_Ayz_1*0.01745;//Convertion from °/s to Radians/s
1556	    Rate_Axz_1 = Rate_Axz_1*0.01745;
1557	    Rate_Axy_1 = Rate_Axy_1*0.01745;
1558	
1559	    /*Combining Accelerometer & Gyroscope Data*/
1560	    Axz_0 = atan2(RxEst_0,RzEst_0);
1561	    Ayz_0 = atan2(RyEst_0,RzEst_0);
1562	    Axy_0 = atan2(RxEst_0,RyEst_0);
1563	
1564	    now_timeperiod = micros();
1565	
1566	    Time_Period = now_timeperiod - lasttime_timeperiod;
1567	
1568	    Axz_1= Axz_0 + Rate_Axz_1*Time_Period*0.000001;
1569	    Ayz_1= Ayz_0 + Rate_Ayz_1*Time_Period*0.000001;
1570	    Axy_1= Axy_0 + Rate_Axy_1*Time_Period*0.000001;
1571	
1572	    lasttime_timeperiod = now_timeperiod;
1573	
1574	    RxGyro = sin(Axz_1)/(sqrt(1.0 + cos(Axz_1)*cos(Axz_1) * tan(Ayz_1)*tan(Ayz_1)));
1575	    RyGyro = sin(Ayz_1)/(sqrt(1.0 + cos(Ayz_1)*cos(Ayz_1) * tan(Axz_1)*tan(Axz_1)));
1576	    if(RzEst_0 >= 0){
1577	      RzGyro = 1.0*sqrt(1 - RxGyro*RxGyro - RyGyro*RyGyro);
1578	    }
1579	    else {
1580	      RzGyro = -1*sqrt(1 - RxGyro*RxGyro - RyGyro*RyGyro);
1581	    }
1582	
1583	    RxEst_1 = RxAcc*0.5 + RxGyro*0.5 ;// Weight of Gyro. over Acc.
1584	    RyEst_1 = RyAcc*0.5 + RyGyro*0.5 ;
1585	    RzEst_1 = RzAcc*0.5 + RzGyro*0.5 ;
1586	
1587	    R_Est = sqrt(RxEst_1*RxEst_1+RyEst_1*RyEst_1+RzEst_1*RzEst_1);
1588	
1589	    Pitch_Sensor = atan2(RxEst_1,sqrt(RyEst_1*RyEst_1)+(RzEst_1*RzEst_1))*180/PI;
1590	    Roll_Sensor = atan2(RyEst_1,sqrt(RxEst_1*RxEst_1)+(RzEst_1*RzEst_1))*180/PI;
1591	
1592	    float magRawX = mx*cos(Pitch_Sensor*PI/180.0f)  - mz*sin(Pitch_Sensor*PI/180.0f);
1593		float magRawY = mx*sin(Roll_Sensor*PI/180.0f)*sin(Pitch_Sensor*PI/180.0f) + my*cos(Roll_Sensor*PI/180.0f)- mz*sin(Roll_Sensor*PI/180.0f)*cos(Pitch_Sensor*PI/180.0f);
1594	    Yaw_Sensor = (180*atan2(magRawY,magRawX)/PI) - Mag_Declination;
1595	
1596	    if(Yaw_Sensor<0)Yaw_Sensor+=360;
