    uint32_t setup_start = HAL_GetTick();
    ret = ad9523_setup(&dev, &init_param);
    DIAG("CLK", "ad9523_setup() returned %ld (took %lu ms)",
         (long)ret, (unsigned long)(HAL_GetTick() - setup_start));
