2174		  /////////////////////////////////////ADAR1000/////////////////////////////////////////
2175		  //////////////////////////////////////////////////////////////////////////////////////
2176		 //phase_step = 0 => phase = 0°
2177		 //phase_step = 127 => phase = 360°
2178		 //steering angle (rad)= arcsin(phase_dif/Pi)
2179	
2180	      runRadarPulseSequence();
2181	
2182	      /* [AGC] Outer-loop AGC: sync enable from FPGA via DIG_6 (PD14),
2183	       * then read saturation flag (DIG_5 / PD13) and adjust ADAR1000 VGA
2184	       * common gain once per radar frame (~258 ms).
2185	       * FPGA register host_agc_enable is the single source of truth —
2186	       * DIG_6 propagates it to MCU every frame.
2187	       * 2-frame confirmation debounce: only change outerAgc.enabled when
2188	       * two consecutive frames read the same DIG_6 value. Prevents a
2189	       * single-sample glitch from causing a spurious AGC state transition.
2190	       * Added latency: 1 extra frame (~258 ms), acceptable for control plane. */
2191	      {
