2831	/**
2832	 * [GAP-3 FIX 2] Initialize Independent Watchdog (IWDG).
2833	 *
2834	 * LSI clock ≈ 32 kHz.
2835	 * Prescaler = 256  → IWDG counter clock ≈ 125 Hz (8 ms/tick).
2836	 * Reload   = 500   → timeout ≈ 500 × 8 ms = 4.0 s.
2837	 *
2838	 * The main loop must call HAL_IWDG_Refresh() within this window
2839	 * or the MCU hard-resets — protecting against firmware hangs when
2840	 * PA rails may be energized.
2841	 */
2842	static void MX_IWDG_Init(void)
2843	{
2844	    hiwdg.Instance       = IWDG;
2845	    hiwdg.Init.Prescaler = IWDG_PRESCALER_256;
2846	    hiwdg.Init.Reload    = 500;
2847	    hiwdg.Init.Window    = IWDG_WINDOW_DISABLE;
2848	    if (HAL_IWDG_Init(&hiwdg) != HAL_OK) {
2849	        DIAG_ERR("SYS", "IWDG init FAILED -- continuing without hardware watchdog");
2850	    } else {
2851	        DIAG("SYS", "IWDG hardware watchdog started (timeout ~4s)");
2852	    }
2853	}
